import{_ as o,o as e,c as t,a as n}from"./app.76824a71.js";const g=JSON.parse('{"title":"iOminous v. Yoahtl, Oct 2019","description":"","frontmatter":{},"headers":[{"level":2,"title":"Case","slug":"case","link":"#case","children":[]},{"level":2,"title":"Proceedings","slug":"proceedings","link":"#proceedings","children":[]}],"relativePath":"government/court-cases-precedents/iominous_v_yoahtl_oct_2019.md","lastUpdated":1666539373000}'),i={name:"government/court-cases-precedents/iominous_v_yoahtl_oct_2019.md"},a=n('<h1 id="iominous-v-yoahtl-oct-2019" tabindex="-1">iOminous v. Yoahtl, Oct 2019 <a class="header-anchor" href="#iominous-v-yoahtl-oct-2019" aria-hidden="true">#</a></h1><h2 id="case" tabindex="-1">Case <a class="header-anchor" href="#case" aria-hidden="true">#</a></h2><p>With Oddish presiding, on 10th October 2019, iOminous sued the Yoahtlan Government for allowing Orinnari to run for Council.</p><h2 id="proceedings" tabindex="-1">Proceedings <a class="header-anchor" href="#proceedings" aria-hidden="true">#</a></h2><p><strong>iOminous:</strong></p><blockquote><p>I&#39;d like to bring a case against the government for allowing Orinarri to run in the October elections with full knowing that he holds office in another nation (Ashelor) - breaking council law 6.5</p></blockquote><p><strong>SpaceVolcano:</strong></p><blockquote><p>The courts will hear the case of iOminous vs the Yoahtlan Goverment the matter of the violation of council law 6.5 regarding Orinnari holding office in Ashelor. Oddish will be presiding judge.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>iOminous can I ask you to make an opening statement for this trial</p></blockquote><p><strong>iOminous:</strong></p><blockquote><p>GDAN will act on my behalf</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>I&#39;d like to charge the government with either knowingly/unknowingly breaking council law 6.5. For reference (&quot;Council 6.5 Dual citizens who do not have primary residence in Yoahtl (excluding vassals and protectorates) or hold office in any other nation are ineligible to run for Council.&quot;)</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>the case is agasint the gov</p></blockquote><blockquote><p>not orinari</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>By allowing Orinnari to continue to run for council even though he is the King of Ashelor. King being the highest office, at the time of this lawsuit beginning, within Ashelor</p></blockquote><blockquote><p>As a resolution I&#39;d like for Orinnari to be removed from the ballot for the run-off elections, to avoid having to redo the entire election procedure. I&#39;d like no other penalties to befall any party.</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>I claim not guilty</p></blockquote><p><strong>Feathercrown:</strong></p><blockquote><p>Wait</p></blockquote><blockquote><p>We have to discuss this as a government</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>No we don&#39;t</p></blockquote><blockquote><p>I&#39;m the self-appointed lawyer for the government</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>Oddish, do I present evidence now?</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>ill assume bg has nothing to say</p></blockquote><blockquote><p>gdan present</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>You don&#39;t, you only have to submit a plea</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/631963737070239754/631988087253237760/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/631963737070239754/631988087253237760/unknown.png</a></p></blockquote><blockquote><p>Orinnari is King in Ashelor, the highest office</p></blockquote><blockquote><p>From decision D007 - Chancellor of Ashelor:</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/631963737070239754/631989977101631498/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/631963737070239754/631989977101631498/unknown.png</a></p></blockquote><blockquote><p>This decision of the government of Ashelor shows without doubt that the Monarch- and therefore king- of Ashelor is the most senior figure within the nation. Since Orinnari holds the position of King, it is without a doubt that he holds office within Ashelor.</p></blockquote><blockquote><p>It is stated in Ashelor&#39;s announcements channel that they are independant of Yoahtl</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/631963737070239754/631990525444227131/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/631963737070239754/631990525444227131/unknown.png</a></p></blockquote><blockquote><p>It is again restated after an enquiry is made as to their status in relation to Yoahtl</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/631963737070239754/631990746060423168/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/631963737070239754/631990746060423168/unknown.png</a></p></blockquote><blockquote><p>I believe that the above evidence demonstrates that council law 6.5 has been broken</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/631963737070239754/631990994581192742/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/631963737070239754/631990994581192742/unknown.png</a></p></blockquote><blockquote><p>Orinnari holds office in a fully independant nation and is therefore ineligible to run for council.</p></blockquote><blockquote><p>I&#39;d like to state that I do not support this law suit to further iOminous&#39; agenda to be installed upon the council as I believe he too may be in violation of a law that would see him eligible, however I have no such proof of this. I&#39;ll state publically now that I&#39;ll be voting for Aki and F1sh in the run-off elections and that this can be taken as my vote.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>i dont think it can be as it isnt an official area to vote</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>This is not a question of friendship, it is a question of upholding our laws. Orinnari has chosen to start his own independent nation of his own free will, this does not mean he should lose citizenship or be disowned as a friend. Duel citizenship is allowed within Yoahtl and he is a long standing friend, this is no argument to lost a friend over.</p></blockquote><blockquote><p>But in this case I believe our laws must be upheld, as we cannot disregard our laws every time a friend asks us to.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>I call bgbba to begin his defence</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>The Charter is superior to the laws, and the Council states that all citizens may run for Council.</p></blockquote><blockquote><p>Since GDAN&#39;s claim rests on a council law, this is a misunderstanding. That council law is overridden by the charter. This is how we allowed other edge cases in the past. Citizenship is the ultimate test of being a Yoahtlan. If as GDAN says Orinnari should still be a citizen, then he should still be allowed to run for Council. Additionally, I dispute GDAN&#39;s claims in public channels about feeling told to &#39;shut up&#39;. This is blatantly untrue, and over the past several months we have implemented all his reforms, changes, and reaffirmations of the important laws and procedures. I&#39;ve come to rely on GDAN as a source of wisdom and legal information, having people like him in Yoahtl is a good thing because it helps keep us on our toes. If there are examples of GDAN actually being told to stop bothering with trying to hold Yoahtlans accountable, then this is a serious problem and should be addressed.</p></blockquote><blockquote><p>However, in this specific case his argument rests on a misinterpretation of the law that hasn&#39;t been used to prevent people from Councillorship in a very long time.</p></blockquote><blockquote><p>I would argue that the law has been superceded and has (over time) lapsed due to lack of justifiable reason for enforcement.</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>Oddish, permission to cross examine?</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>yes</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>Firstly, I would like to make the point that there is no guarantee within the charter that all citizens may run for council. Neither does the charter state that the council must consist of citizens. Hence the charter does not grant all citizens an unwavering right to run for council regardless of other laws.</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>Then where does it state you need to be citizen to run for Council?</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>I&#39;m getting to that</p></blockquote><blockquote><p>Secondly, the idea that the charter is superior to council/ololtic law stems from a misrepresentation of a piece of case precedent that was never corrected.</p></blockquote><blockquote><p>I believe that the following:</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/631963737070239754/631998841616596992/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/631963737070239754/631998841616596992/unknown.png</a></p></blockquote><blockquote><p>Has been slowly misinterpreted over time and the original document forgotten so that the idea that the charter is superior to council/ololtic laws became prevalent although it actually holds no standing.</p></blockquote><blockquote><p>Thirdly, even if the charter did take precedent it would not matter. Since it is taken from council law 10.2 that you need be a citizen to run for council.</p></blockquote><blockquote><p><a href="https://cdn.discordapp.com/attachments/631963737070239754/631999489930166272/unknown.png" target="_blank" rel="noreferrer">https://cdn.discordapp.com/attachments/631963737070239754/631999489930166272/unknown.png</a></p></blockquote><blockquote><p>If it were the case that the charter took precedent then this would still be of equal merit to council law 6.5</p></blockquote><blockquote><p>Since 10.2 is only implying that you need be a citizen to run but 6.5 is stating that you cannot run under certain circumstances it should be taken that the conditions set forth by 6.5 are not optional.</p></blockquote><blockquote><p>Fourthly, I would like to point out that the only reason the length of time between some of our laws being used and the present is only so long due to the period of time from just before CivEx to after CivEx where the majority of our laws, precedent and even our elections were forgotten and that the extensive length of time is not then a reason to ignore laws that are not contradicted.</p></blockquote><blockquote><p>Lastly, I&#39;d like to again state that this is not an attack on Orinnari. But is instead an attempt to uphold the integrity of our system of governance, to maintain the laws of our nation and to give a voice to those in our nation who do wish to see our laws upheld even if that means against a longterm friend and trusted Yoahtlan.</p></blockquote><blockquote><p>Orinnari himself chose to start an independent nation, it was up to no one else to put him into a position where he&#39;s in contempt of the law. Therefore, our laws should be respected and if Orinnari does wish to run for council to fix the organisation of our discord then I personally would welcome Ashelor as a non-auto town or a homestead.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>bgbba cross examine</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>I have nothing to present</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>Right so I&#39;d like to clarify somethigs</p></blockquote><blockquote><p>This is because Ori is a king in his own nomination of how many people?</p></blockquote><blockquote><p>That&#39;s sorta 2 questions there</p></blockquote><p><strong>iOminous:</strong></p><blockquote><p>Sorry, I dont really understand what you’re asking</p></blockquote><blockquote><p>Orinnari has primary residence in Ashelor. A nation that he is the King of.</p></blockquote><blockquote><p>While also running for councillor on the side.</p></blockquote><blockquote><p>to put it shortly, its dual mandate</p></blockquote><blockquote><p>something prohibited by the charter rules</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>Oddish, No matter rhe size of the nation, it is still an inpendent nationo over which Ori rules. Hence he holds the highest office possible within the nation as I showed.</p></blockquote><blockquote><p>If I today declared my homestead an independent nation, it would be an independent nation.</p></blockquote><blockquote><p>There is no difference because of it&#39;s size. Orinnari chose tp start Ashelor of his own free volition. We shouldn&#39;t be creating precedent from this case that it&#39;s ok for every citizen to begin their own micro nations and then still participate fully and wholly within yoahtl governance by running for council.</p></blockquote><blockquote><p>Furthermore, the current size of the nation does not mean it won&#39;t grow larger over time.</p></blockquote><p><strong>Orinnari:</strong></p><blockquote><blockquote><p>Just so you know, I&#39;m officially withdrawing from the runoff election. GDAN seems content with being a pawn in iOminous&#39; play for power. I get that I&#39;m doing exactly what iOminous wants here, I figure he thought he could either legally remove me from the ballot or frustrate me out of running and congrats my dude, you managed it. I wanted to serve Yoahtl, make the proposal system better and more legible... but it seems that people would rather block me from doing so unless I wholesale change the status of a town they don&#39;t care one iota about. But eh, this is too much work just to do the work that councillors can&#39;t be bothered to do themselves... soooo... good luck.</p></blockquote></blockquote><blockquote><p>This was posted nine hours ago in #deleted-channel, I have officially withdrawn from the runoff election because I&#39;ve felt the hassle around me being elected merely to manage the proposal system to be too much. So unless the purpose of this trial is to doubly remove me from the ballot, you can stop this facade of trying to fairly enforce the law now.</p></blockquote><p><strong>Feathercrown:</strong></p><blockquote><p>The trial is now determining precedent</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>I&#39;m also trying to understand this whole situation</p></blockquote><blockquote><p>Because I know this isn&#39;t the only case</p></blockquote><blockquote><p>So Ori is a leader in another nation and ran for council here.</p></blockquote><blockquote><p>bgbba, was neo.tide running a nation with a seat of power when he ran for elections here ?</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>Yes</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>So how was he allowed to run for elections then</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>Because he was active in Yoahtl and in practice his role of leader in those other towns had grown small</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>Right so because he didint so much there but did a lot here he was allowed to run</p></blockquote><blockquote><p>New question.</p></blockquote><blockquote><p>Isn&#39;t fish leader of okato or okashima</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>Yes</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>would it not be against our own laws as well to let him run?</p></blockquote><blockquote><p>as he currently is</p></blockquote><blockquote><p>or is there something im missing here</p></blockquote><p><strong>Orinnari:</strong></p><blockquote><p>(I think Okashima is a non-auto town)</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>does that matter?</p></blockquote><p><strong>Orinnari:</strong></p><blockquote><p>If they&#39;re non-autonomous, then they&#39;re under the jurisdiction of the Yoahtlan government and so have full rights as citizens to run for that government. The same is not true for autonomous towns.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>can we confirm if okashima is a non auto</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>Yes it is</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>and oris right in his thinking?</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>That what</p></blockquote><p><strong>Orinnari:</strong></p><blockquote><p>I think Oddish is asking whether I&#39;m right in saying that F1sh is able to run as a candidate because Okashima is non-autonomous</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>Yes</p></blockquote><blockquote><p>He is</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>Judgement for the prosecution</p></blockquote><blockquote><p>Orinnari should not have run this election due to holding a seat of power within another nation and being currently active in said nation. However as he has already withdrawn from the elections I cant decree to remove him as this case would have wanted.</p></blockquote><blockquote><p>This is a fault on our part as a Government to not see this sooner. TBH personally I didnt know he had another nation let alone rule in it. As for the rest of the council and government as a whole I dont know.</p></blockquote><blockquote><p>Im not sure what to do here</p></blockquote><p><strong>Orinnari:</strong></p><blockquote><p>The first thing is that you should decree that NeoTide be immediately removed from office for the same infraction.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>he isnt council</p></blockquote><blockquote><p>I guess that in the case of Neotides situation IF They are active within our nation more then the nation they hold a seat to and have been given express permission to run in elections They can run. If not then well they cant run for elections</p></blockquote><blockquote><p>he was effectively given permission to run down to the fact he then later gave that power up</p></blockquote><blockquote><p>nothing was brought up then afaik and we cant remove him from a council when his term is over and will be leaving it</p></blockquote><blockquote><p>holding general role does not require council</p></blockquote><blockquote><p>or running for it</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>No one chose to sue Neo or the gov at the time so it was never an issue. I assume if someone had chosen to do so Neo would&#39;ve just given his position in Okashima up as at the time Okashima was largely inactive.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>That would have been the case</p></blockquote><p><strong>bgbba:</strong></p><blockquote><p>Yes it would have</p></blockquote><blockquote><p>And he did as soon as f1sh returned</p></blockquote><p><strong>GDAN:</strong></p><blockquote><p>From now on I will be bringing to court any case where our laws are being infracted so as to either set new precedent or to uphold the law. Just because a law was ignored in the past/no one bothered with sueing over it doesn&#39;t mean it shouldn&#39;t continue to exist.</p></blockquote><blockquote><p>Instead of just creating an arguement in another channel over the law being broken I&#39;ll be bringing cases straight to the courthouse in the future.</p></blockquote><p><strong>Oddish:</strong></p><blockquote><p>This case will serve as a precedent for future issues. If an injunction is filed against somebody’s eligibility for council They will be investigated and thus removed from the pool if found in breach of our laws</p></blockquote><blockquote><p>people can contest somebody’s eligibility on the grounds of citizenship I will extend this to foreign offices and non-primary residency for dual citizens</p></blockquote>',172),s=[a];function r(l,c,h,u,p,d){return e(),t("div",null,s)}const k=o(i,[["render",r]]);export{g as __pageData,k as default};
